import './style.css';
import UmapComponent from "./Components/UMAPComponent";
import TableComponent from "./Components/TableComponent";
import StarplotComponent from "./Components/StarplotComponent";
import ConfigureComponent from './Components/ConfigureComponent';
import ProjectionsComponent from './Components/ProjectionsComponent';


import { Component } from 'preact';
import * as d3 from 'd3';

export default class App extends Component {

constructor(){
	super()
  this.state = {
		UMAP_data: [],//data para dibujar el UMAP - data[0] umap all features, data[1] end-members
    data: [],  //data total con los elementos quimicos, categorias y subcategorias por muestra
    selected_data: [], //data "seleccionada" en UMAP/Configure
		highlighted_data: [], //data "resaltada" en Table/Projections
    dropDownOption:-1, // opcion seleccionada en UMAP
		flag : 1, //flag para detectar quien "selecciono puntos" -> 0 (Config) / (1) UMAP
  }
  this.update_selected_data = this.update_selected_data.bind(this);
	this.update_highlighted_data  = this.update_highlighted_data.bind(this);
  this.update_dropDownOption =  this.update_dropDownOption.bind(this);
}

/**
 * Se invoca antes de que se monte el componente.
 * Carga los datos para dibujar el UMAP y los datos totales de muestras
 */

componentWillMount() {
  let data_file = [];
  let files_name=['assets/data/cocientes+cocTi_25_0.25.csv','assets/data/cocientes+cocTi_50_0.25.csv','assets/data/cocientes+cocTi_75_0.25.csv',
	'assets/data/cocientes+TiO2_25_0.25.csv','assets/data/cocientes+TiO2_50_0.25.csv','assets/data/cocientes+TiO2_75_0.25.csv',
	'assets/data/endmembersEMG.csv','assets/data/endmembers_EMG+.csv'];

  for(let i = 0; i<files_name.length;i++){
    let d = [];
    d3.csv(files_name[i]).then(function(data) {
      for(let j = 0; j<data.length; j++){
        d.push({
          i:j,
          umap1: +data[j].umap1,
          umap2: +data[j].umap2,
					Category:data[j].cat
        })
      }
    }).catch(function(err) {
        throw err;
    })
    data_file.push(d);
  }

  let data_f = [];
  d3.csv('assets/data/filtrado_GABI.csv').then(function(data) {
    for(let j = 0; j<data.length; j++){
      data_f.push({
				i:j,
				Ref:data[j].Ref,
				SiO2: (+data[j].SiO2).toFixed(4),
				TiO2: (+data[j].TiO2).toFixed(4),
				V2O3: (+data[j].V2O3).toFixed(4),
				Al2O3: (+data[j].Al2O3).toFixed(4),
				Cr2O3: (+data[j].Cr2O3).toFixed(4),
				FeO: (+data[j].FeO).toFixed(4),
				Fe2O3: (+data[j].Fe2O3).toFixed(4),
				MnO: (+data[j].MnO).toFixed(4),
				MgO: (+data[j].MgO).toFixed(4),
				NiO: (+data[j].NiO).toFixed(4),
				ZnO: (+data[j].ZnO).toFixed(4),
				Cr: (+data[j].Cr).toFixed(4),
				Ti: (+data[j].Ti).toFixed(4),
				Al: (+data[j].Al).toFixed(4),
				Fe3: (+data[j].Fe3).toFixed(4),
				Fe2: (+data[j].Fe2).toFixed(4),
				Mn: (+data[j].Mn).toFixed(4),
				Mg: (+data[j].Mg).toFixed(4),
				Ni: (+data[j].Ni).toFixed(4),
				Zn: (+data[j].Zn).toFixed(4),
				Xtriplot: (+data[j].Xtriplot).toFixed(4),
				Ytriplot: (+data[j].Ytriplot).toFixed(4),

				Category1:data[j].Category1,
				Category2:data[j].Category2,
      })
    }
  });
  this.setState({data:data_f});
  this.setState({UMAP_data:data_file});
}

/*
* Callback - data seleccionados
*/
update_selected_data(f,data){
  this.setState({flag:f},()=>this.setState({selected_data:data}));
}

/*
* Callback - data resaltados
*/
update_highlighted_data(data){
  this.setState({highlighted_data:data});
}

/*
* Callback - dropDownOption - opcion de UMAP
*/
update_dropDownOption(option){
  this.setState({dropDownOption:option});
}

render(){
  var data = this.state.data;
	var UMAP_data = this.state.UMAP_data;
  var selected_data =  this.state.selected_data;
	var highlighted_data =  this.state.highlighted_data;
  var dropDownOption = this.state.dropDownOption;

  return(
    <div>
      //Navbar starts
      <header class="header">
        <div id="menu" class="fas fa-bars"></div>
          <nav class="navbar">
            <ul>
              <li><a class="active" href="#dashboard">Dashboard</a></li>
							<li><a href="#projections">Projections</a></li>
              <li><a href="#traditional">Table</a></li>
              <li><a href="#footer">Footer</a></li>
            </ul>
          </nav>
      </header>

      <section class="dashboard" id="dashboard">
        <div class="container">
          <div class="content">
						<UmapComponent UMAP_data={UMAP_data} data={data} flag={this.state.flag} highlighted_data={highlighted_data} selected_data={selected_data} dropDownOption={dropDownOption}  callback_dropDownOption={this.update_dropDownOption} callback_selected_data={this.update_selected_data}/>
					</div>
          <div class="content">
						<ConfigureComponent data={data} flag={this.state.flag} selected_data={selected_data}  callback_selected_data={this.update_selected_data}/>
					</div>
					<div class="content">
					</div>

        </div>
      </section>
      <section class="projections" id="projections">
          <ProjectionsComponent data={data} selected_data={selected_data} highlighted_data={highlighted_data} callback_highlighted_data={this.update_highlighted_data}/>
			</section>

      <section class="traditional" id="traditional">
        <div class="row">
					<div class="container-Table" >
						<TableComponent  data={data} selected_data={selected_data} dropDownOption={dropDownOption} highlighted_data={highlighted_data} callback_highlighted_data={this.update_highlighted_data}/>
					</div>
        </div>
      </section>

      <section class="footer" id="footer">
        <div class="box-container">
          <div class="box">
            <h3>Others</h3>
            <p>... <br/> <br/></p>
          </div>
          <div class="box">
            <h3>Others</h3>
          </div>
          <div class="box">
            <h3>Others</h3>
          </div>
        </div>
      </section>
      <a href="#dashboard" aria-label="ScrollTop" class="fas fa-angle-up" id="scroll-top"></a>
    </div>
  );
}
}

